DDL:
DROP TABLE IF EXISTS DIM_GEOGRAPHY_HIERARCHY CASCADE;
CREATE TABLE DIM_GEOGRAPHY_HIERARCHY (
	GEOGRAPHY_ID BIGINT PRIMARY KEY,
	STATE_CODE VARCHAR(50),
	DISTRICT_CODE BIGINT,
	PSU_CODE BIGINT
);

DROP TABLE IF EXISTS DIM_GEOGRAPHY_DETAIL CASCADE;
CREATE TABLE DIM_GEOGRAPHY_DETAIL (
	LOCATION_ID BIGINT PRIMARY KEY,
	LOCATION_NAME VARCHAR(30)
);

DROP TABLE IF EXISTS DIM_HOUSEHOLD_STATUS CASCADE;
CREATE TABLE DIM_HOUSEHOLD_STATUS (
	HOUSEHOLD_STATUS_ID BIGINT PRIMARY KEY,
	COMPLETION_STATUS VARCHAR(30),
	COMPLETION_STATUS_OTHER VARCHAR(50)
);

DROP TABLE IF EXISTS DIM_PERSON_STATUS CASCADE;
CREATE TABLE DIM_PERSON_STATUS (
	PERSON_STATUS_ID BIGINT PRIMARY KEY,
	TRACKING_STATUS BIGINT,
	RELATIONSHIP_TO_HEAD VARCHAR(30)
);

DROP TABLE IF EXISTS DIM_DEMOGRAPHIC_CODES CASCADE;
CREATE TABLE DIM_DEMOGRAPHIC_CODES (
	DEMOGRAPHIC_CODE_ID BIGINT PRIMARY KEY,
	SEX_CODE VARCHAR(20),
	MARITAL_STATUS_CODE VARCHAR(20)
);

DROP TABLE IF EXISTS DIM_OCCUPATION_CODES CASCADE;
CREATE TABLE DIM_OCCUPATION_CODES (
	OCCUPATION_ID BIGINT PRIMARY KEY,
	OCCUPATION_CODE VARCHAR(50),
	OCCUPATION_DESCRIPTION VARCHAR(50)
);

DROP TABLE IF EXISTS DIM_EMPLOYMENT_STATUS CASCADE;
CREATE TABLE DIM_EMPLOYMENT_STATUS (
	EMPLOYMENT_STATUS_ID BIGINT PRIMARY KEY,
	ACTIVITY_STATUS VARCHAR(30),
	EMPLOYMENT_TYPE VARCHAR(30)
);

DROP TABLE IF EXISTS DIM_MIGRATION_REASONS CASCADE;
CREATE TABLE DIM_MIGRATION_REASONS (
	MIGRATION_REASON_ID BIGINT PRIMARY KEY,
	REASON_DESCRIPTION VARCHAR(30)
);

DROP TABLE IF EXISTS FACT_HOUSEHOLD_TRACKING CASCADE;
CREATE TABLE FACT_HOUSEHOLD_TRACKING (
	HOUSEHOLD_TRACKING_ID BIGINT PRIMARY KEY,
	HOUSEHOLD_ID BIGINT,
	SAME_ADDRESS_INDICATOR VARCHAR(20),
	FOREIGN KEY (HOUSEHOLD_ID) REFERENCES FACT_HOUSEHOLD_CORE (HOUSEHOLD_ID)
);

DROP TABLE IF EXISTS FACT_DECEASED_OCCUPATION CASCADE;
CREATE TABLE FACT_DECEASED_OCCUPATION (
	DECEASED_OCCUPATION_ID BIGINT PRIMARY KEY,
	DECEASED_ID BIGINT,
	OCCUPATION_ID BIGINT,
	EMPLOYED_AT_DEATH VARCHAR(20),
	FOREIGN KEY (DECEASED_ID) REFERENCES FACT_DECEASED_PERSON_DETAILS (DECEASED_ID),
	FOREIGN KEY (OCCUPATION_ID) REFERENCES DIM_OCCUPATION_CODES (OCCUPATION_ID)
);

DROP TABLE IF EXISTS FACT_MIGRANT_PERSONAL CASCADE;
CREATE TABLE FACT_MIGRANT_PERSONAL (
	MIGRANT_ID BIGINT PRIMARY KEY,
	PERSON_ID BIGINT,
	MARITAL_STATUS_AT_MIGRATION_CODE VARCHAR(30),
	EDUCATION_AT_MIGRATION_CODE VARCHAR(30),
	MARRIED_WHEN_MIGRATED_INDICATOR VARCHAR(20),
	FOREIGN KEY (PERSON_ID) REFERENCES FACT_PERSON_CORE (PERSON_ID)
);

DROP TABLE IF EXISTS FACT_MIGRANT_EMPLOYMENT CASCADE;
CREATE TABLE FACT_MIGRANT_EMPLOYMENT (
	MIGRANT_EMPLOYMENT_ID BIGINT PRIMARY KEY,
	MIGRANT_ID BIGINT,
	EMPLOYMENT_STATUS_ID BIGINT,
	OCCUPATION_ID BIGINT,
	FOREIGN KEY (MIGRANT_ID) REFERENCES FACT_MIGRANT_PERSONAL (MIGRANT_ID),
	FOREIGN KEY (EMPLOYMENT_STATUS_ID) REFERENCES DIM_EMPLOYMENT_STATUS (EMPLOYMENT_STATUS_ID),
	FOREIGN KEY (OCCUPATION_ID) REFERENCES DIM_OCCUPATION_CODES (OCCUPATION_ID)
);

DROP TABLE IF EXISTS FACT_MIGRATION_LOGISTICS CASCADE;
CREATE TABLE FACT_MIGRATION_LOGISTICS (
	MIGRATION_LOGISTICS_ID BIGINT PRIMARY KEY,
	MIGRANT_ID BIGINT,
	MIGRATION_FACILITATED_BY VARCHAR(30),
	SPOUSE_LOCATION VARCHAR(30),
	FOREIGN KEY (MIGRANT_ID) REFERENCES FACT_MIGRANT_PERSONAL (MIGRANT_ID)
);
